import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]]): Long = {
  val N = n.toInt
  val graph = Array.fill(N)(mutable.ListBuffer[(Int, Long)]())
  val reversedGraph = Array.fill(N)(mutable.ListBuffer[(Int, Long)]())

  for (e <- edges) {
    val u = e(0).toInt
    val v = e(1).toInt
    val w = e(2)
    graph(u).append((v, w))
    reversedGraph(v).append((u, w))
  }

  val dist = Array.fill(N, 2)(Long.MaxValue)
  dist(0)(0) = 0
  val heap = mutable.PriorityQueue[(Long, Int, Int)]()(Ordering.by(-_._1))
  heap.enqueue((0L, 0, 0))

  while (heap.nonEmpty) {
    val (currentDist, u, used) = heap.dequeue()
    if (u == N - 1) return currentDist
    if (currentDist > dist(u)(used)) () 
    else {
      // Normal edges
      for ((v, w) <- graph(u)) {
        val newDist = currentDist + w
        if (newDist < dist(v)(used)) {
          dist(v)(used) = newDist
          heap.enqueue((newDist, v, used))
        }
      }
      // Try to use the switch if not used yet
      if (used == 0) {
        for ((v, w) <- reversedGraph(u)) {
          val newDist = currentDist + 2 * w
          if (newDist < dist(v)(1)) {
            dist(v)(1) = newDist
            heap.enqueue((newDist, v, 1))
          }
        }
      }
    }
  }

  val res = math.min(dist(N - 1)(0), dist(N - 1)(1))
  if (res == Long.MaxValue) -1 else res
}
