def solve(n: Long, edges: Array[Array[Long]]): Long = {
    val graph = Array.fill(n.toInt)(mutable.ListBuffer[(Int, Long)]())
    val reversedGraph = Array.fill(n.toInt)(mutable.ListBuffer[(Int, Long)]())

    for (edge <- edges) {
        val u = edge(0).toInt
        val v = edge(1).toInt
        val w = edge(2)
        graph(u).append((v, w))
        reversedGraph(v).append((u, w))
    }

    val heap = mutable.PriorityQueue.empty[(Long, Int, Boolean)](Ordering.by(-_._1))
    heap.enqueue((0L, 0, false))

    val dist = Array.fill(n.toInt, 2)(Long.MaxValue)
    dist(0)(0) = 0

    while (heap.nonEmpty) {
        val (currentDist, u, usedFlip) = heap.dequeue()
        if (u == n - 1) return currentDist
        if (currentDist > dist(u)(if (usedFlip) 1 else 0)) {
            // Skip if we already found a better path
            // This is crucial for performance
            ()
        } else {
            // Case 1: don't use flip at u
            for ((v, w) <- graph(u)) {
                val newDist = currentDist + w
                if (newDist < dist(v)(if (usedFlip) 1 else 0)) {
                    dist(v)(if (usedFlip) 1 else 0) = newDist
                    heap.enqueue((newDist, v, usedFlip))
                }
            }
            // Case 2: use flip at u if not used before
            if (!usedFlip) {
                for ((v, w) <- reversedGraph(u)) {
                    val newDist = currentDist + 2 * w
                    if (newDist < dist(v)(1)) {
                        dist(v)(1) = newDist
                        heap.enqueue((newDist, v, true))
                    }
                }
            }
        }
    }

    val res = math.min(dist((n - 1).toInt)(0), dist((n - 1).toInt)(1))
    if (res == Long.MaxValue) -1 else res
}
